import React, { useState } from 'react';
import axios from 'axios';
import SpecialistAreas from '../components/SpecialistAreas';

const ContactUs = () => {
  const [formData, setFormData] = useState({
    name: '',
    emailId: '',
    phone: '',
    subject: '',
    message: ''
  });
  const [status, setStatus] = useState({ type: '', message: '' });
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setStatus({ type: '', message: '' });

    try {
      const response = await axios.post('/api/contact', formData);
      if (response.data.success) {
        setStatus({ type: 'Success32', message: response.data.message });
        setFormData({
          name: '',
          emailId: '',
          phone: '',
          subject: '',
          message: ''
        });
      }
    } catch (error) {
      setStatus({ 
        type: 'Error32', 
        message: error.response?.data?.message || 'Error submitting contact form' 
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="pageCntsContainer">
      <table cellpadding="0" border="0" cellspacing="0" width="100%">
        <tbody>
          <tr>
            <td width="70%">
              <table cellpadding="2" cellspacing="0" border="0" width="100%">
                <tbody>
                  <tr>
                    <td>
                      <span className="PageHeader">Contact Us</span>
                    </td>
                  </tr>
                  <tr>
                    <td align="center">
                      <img 
                        src="/images/Common/contactus.png" 
                        alt="Contact Us" 
                        title="Contact Us"
                        align="absMiddle"
                      />
                    </td>
                  </tr>
                  <tr>
                    <td style={{ height: '25px' }} colSpan={2}>
                      &nbsp;
                    </td>
                  </tr>
                  <tr>
                    <td>
                      <div className="ContUsContainer">
                        {status.message && (
                          <div className={`errorContainer ${status.type}`}>
                            {status.message}
                          </div>
                        )}
                        <table cellpadding="5" cellspacing="0" border="0" width="100%">
                          <tbody>
                            <tr>
                              <td width="25%" className="ContUsLabel">
                                Company Name :-
                              </td>
                              <td className="ContUsCompanyName">
                                Sun Emirates Mechanical Works LLC
                              </td>
                            </tr>
                            <tr>
                              <td className="ContUsLabel">
                                Address :-
                              </td>
                              <td className="ContUsAddress">
                                P.O.Box : 14655, Ajman - U.A.E.
                              </td>
                            </tr>
                            <tr>
                              <td className="ContUsLabel">
                                Telephone No :-
                              </td>
                              <td className="ContUsTelNo">
                                +971-6-7481646
                              </td>
                            </tr>
                            <tr>
                              <td className="ContUsLabel">
                                Fax No :-
                              </td>
                              <td className="ContUsFaxNo">
                                +971-6-7481647
                              </td>
                            </tr>
                            <tr>
                              <td className="ContUsLabel">
                                Mobile No :-
                              </td>
                              <td className="ContUsMobileNo">
                                +971-50-7743556
                              </td>
                            </tr>
                            <tr>
                              <td className="ContUsLabel">
                                E-Mail Id :-
                              </td>
                              <td className="ContUsEMailId">
                                <a href="mailto:sales@sunemirates.com">sales@sunemirates.com</a><br />
                                <a href="mailto:saminathan@sunemirates.com">saminathan@sunemirates.com</a><br />
                                <a href="mailto:sunemw@eim.ae">sunemw@eim.ae</a>
                              </td>
                            </tr>
                          </tbody>
                        </table>
                      </div>
                    </td>
                  </tr>
                </tbody>
              </table>
            </td>
            <td width="30%" valign="top" className="osa">
              <SpecialistAreas />
            </td>
          </tr>
          <tr>
            <td style={{ height: '25px' }} colSpan={2}>
              &nbsp;
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  );
};

export default ContactUs;
